class PhysicsInformedLoss(nn.Module):
    def forward(self, prediction, target, physics_constraint):
        mse = F.mse_loss(prediction, target)
        physics_penalty = torch.mean(torch.abs(physics_constraint(prediction)))
        return mse + 0.1 * physics_penalty

